// src/components/FilterBar/index.jsx

import React, { useEffect } from 'react';
import { useForm } from 'react-hook-form';
import { useDispatch, useSelector } from 'react-redux';
import { setProductsFilter } from '../../store/slices/productsSlice'; // <-- Новый экшен
import Button from '../UI/Button';
import s from './FilterBar.module.css';

const FilterBar = () => {
  const dispatch = useDispatch();
  const currentFilters = useSelector(state => state.products.filters);

  // Инициализация формы с текущими значениями из Redux
  const { 
    register, 
    handleSubmit, 
    watch, 
    setValue, 
    reset 
  } = useForm({
    defaultValues: {
      priceFrom: currentFilters.priceFrom,
      priceTo: currentFilters.priceTo,
      discount: currentFilters.discount,
      sortBy: currentFilters.sortBy,
    }
  });

  // Отслеживаем изменения во всех полях формы
  const watchedFields = watch();

  // Эффект, который запускается при любом изменении полей формы
  useEffect(() => {
    // Динамический диспатч фильтров в Redux при изменении любого поля (кроме reset)
    // Преобразуем строковые значения цен в числа для Redux
    const payload = {
      priceFrom: watchedFields.priceFrom,
      priceTo: watchedFields.priceTo,
      discount: watchedFields.discount,
      sortBy: watchedFields.sortBy,
    };

    // Отправляем фильтры в Redux
    dispatch(setProductsFilter(payload));
  }, [watchedFields, dispatch]);


  // Обработчик для сброса фильтров
  const handleClearFilters = () => {
    // Сброс формы в начальное состояние
    reset({
        priceFrom: '',
        priceTo: '',
        discount: false,
        sortBy: 'default'
    });
    // Redux автоматически обновится через useEffect
  };

  // NOTE: Мы используем useEffect + watch для мгновенного применения фильтров.
  // Если нужна кнопка "Применить", то логика должна быть внутри handleSubmit.

  return (
    <div className={s.filterBar}>
      <form className={s.form}>

        {/* Фильтр по цене */}
        <div className={s.group}>
          <label className={s.label}>Price:</label>
          <input 
            type="number" 
            placeholder="from" 
            className={s.input}
            {...register('priceFrom')} 
          />
          <input 
            type="number" 
            placeholder="to" 
            className={s.input}
            {...register('priceTo')} 
          />
        </div>
        {/* Фильтр по скидке */}
        <div className={s.group}>
          <label className={s.label}>Только со скидкой</label>
          <input 
            type="checkbox" 
            className={s.checkbox}
            {...register('discount')} 
          />
        </div>


        {/* Сортировка */}
        <div className={s.group}>
          <label className={s.label}>Sort by:</label>
          <select className={s.select} {...register('sortBy')}>
            <option value="default">default</option>
            <option value="price_asc">price (ascending)</option>
            <option value="price_desc">price (descending)</option>
            <option value="title_asc">title (A-Z)</option>
            <option value="title_desc">title (Z-A)</option>
          </select>
        </div>

        <Button 
            type="secondary" 
            onClick={handleClearFilters}
            className={s.resetButton}
        >
            Reset
        </Button>
      </form>
    </div>
  );
};

export default FilterBar;
